// Parse Medium RSS XML without external modules.
const config = $('SetImporterConfig').first().json;
const raw = $input.first().json;
const xml = String(raw?.data ?? raw?.body ?? raw ?? '');

if (config.mediumRssUrl.includes('YOUR_MEDIUM_USERNAME')) {
  throw new Error('SetImporterConfig.mediumRssUrl must be replaced with your Medium RSS URL');
}
if (config.qdrantBaseUrl.includes('YOUR-QDRANT-CLUSTER')) {
  throw new Error('SetImporterConfig.qdrantBaseUrl must be replaced with your Qdrant Cloud URL');
}

const decode = (value) => String(value ?? '')
  .replace(/<!\[CDATA\[|\]\]>/g, '')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&amp;/g, '&')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'");

const extract = (block, tag) => {
  const match = block.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`, 'i'));
  return decode(match?.[1] ?? '').trim();
};

const stripHtml = (html) => decode(html)
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/p>/gi, '\n\n')
  .replace(/<[^>]+>/g, ' ')
  .replace(/[ \t]+/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const blocks = xml.match(/<item>[\s\S]*?<\/item>/gi) ?? [];

return blocks.map((block) => {
  const title = extract(block, 'title');
  const url = extract(block, 'link');
  const publishedAt = extract(block, 'pubDate');
  const encoded = extract(block, 'content:encoded') || extract(block, 'description');
  const text = stripHtml(encoded);

  return {
    json: {
      title,
      url,
      publishedAt,
      text,
      qdrantBaseUrl: String(config.qdrantBaseUrl).replace(/\/$/, ''),
      collection: config.collection,
      embeddingModel: config.embeddingModel,
      chunkSize: Number(config.chunkSize),
      chunkOverlap: Number(config.chunkOverlap)
    }
  };
}).filter((item) => item.json.url && item.json.text);

// Split every article into overlapping text chunks.
const output = [];

const makeUuid = (text) => {
  let h1 = 0x811c9dc5;
  let h2 = 0x01000193;
  for (let i = 0; i < text.length; i++) {
    h1 = Math.imul(h1 ^ text.charCodeAt(i), 16777619);
    h2 = Math.imul(h2 ^ text.charCodeAt(i), 2246822519);
  }
  const hex = (value, size) => (value >>> 0).toString(16).padStart(size, '0').slice(-size);
  return `${hex(h1,8)}-${hex(h2,4)}-4${hex(h1^h2,3)}-8${hex(h2^0xabcdef,3)}-${hex(h1+h2,8)}${hex(h1^0x12345678,4)}`;
};

for (const item of $input.all()) {
  const data = item.json;
  const size = Math.max(200, data.chunkSize);
  const overlap = Math.max(0, Math.min(data.chunkOverlap, size - 1));
  const step = size - overlap;

  for (let start = 0, index = 0; start < data.text.length; start += step, index++) {
    const text = data.text.slice(start, start + size).trim();
    if (text.length < 80) continue;

    output.push({
      json: {
        pointId: makeUuid(`${data.url}#${index}`),
        title: data.title,
        url: data.url,
        publishedAt: data.publishedAt,
        section: `chunk-${index + 1}`,
        text,
        qdrantBaseUrl: data.qdrantBaseUrl,
        collection: data.collection,
        embeddingModel: data.embeddingModel
      }
    });
  }
}

return output;

// Attach the embedding vector to the original chunk.
const response = $input.first().json;
const chunk = $('ChunkArticles').item.json;
const vector = response.data?.[0]?.embedding;

if (!Array.isArray(vector) || vector.length === 0) {
  throw new Error('NVIDIA embedding response does not contain data[0].embedding');
}

return [{ json: { ...chunk, vector } }];

