// Return a compact import result for each chunk.
const response = $input.first().json;
const chunk = $('AttachEmbedding').item.json;

return [{
  json: {
    pointId: chunk.pointId,
    title: chunk.title,
    url: chunk.url,
    section: chunk.section,
    collection: chunk.collection,
    operationStatus: response.status ?? response.result?.status ?? 'completed',
    metadata: {
      workflow: '05a-medium-style-importer',
      version: '0.5.0',
      embeddingModel: chunk.embeddingModel,
      importedAt: new Date().toISOString()
    }
  }
}];
